import { mcpilot } from '@mcpilotx/sdk-core';

async function runDemo() {
  console.log('🎯 MCPilot SDK Zero-Config Demo');
  console.log('='.repeat(50));

  try {
    // 1. Initialize SDK
    console.log('\n📦 Step 1: Initializing MCPilot SDK...');
    console.log('✅ SDK ready to use!');

    // 2. Show configuration
    console.log('\n⚙️  Step 2: Current Configuration');
    const config = mcpilot.getConfig();
    console.log(`AI configured: ${config.ai ? 'Yes' : 'No'}`);
    console.log(`Services: ${config.services ? Object.keys(config.services).length : 0}`);

    // 3. Demonstrate AI functionality status
    console.log('\n🤖 Step 3: AI Functionality Status');
    console.log('⚠️  Note: AI features require configuration with real API keys');
    console.log('💡 To enable AI, call: mcpilot.configureAI({ provider: \'openai\', apiKey: \'YOUR_KEY\' })');

    // 4. Try to use AI (will show clear error)
    console.log('\n💬 Step 4: Testing AI Query (Expected to fail with clear error)');
    try {
      await mcpilot.ask('Hello, can you help me?');
    } catch (error: any) {
      console.log(`✅ Expected error: ${error.message}`);
      console.log('✅ This demonstrates clear error messaging when AI is not configured');
    }

    // 5. Show MCP capabilities
    console.log('\n🔌 Step 5: MCP Capabilities');
    console.log('🚀 MCPilot SDK supports connecting to any MCP-compatible server:');
    console.log('   - @modelcontextprotocol/server-filesystem');
    console.log('   - @modelcontextprotocol/server-weather');
    console.log('   - @modelcontextprotocol/server-github');
    console.log('   - And many more...');

    console.log('\n🎉 Demo Complete!');
    console.log('='.repeat(50));
    console.log('\n📚 Next Steps:');
    console.log('1. Install a real MCP server: npm install @modelcontextprotocol/server-filesystem');
    console.log('2. Connect to it: await mcpilot.connectMCPServer(...)');
    console.log('3. Configure AI: mcpilot.configureAI({ provider: \'openai\', apiKey: \'YOUR_KEY\' })');
    console.log('4. Explore more examples in the documentation');

  } catch (error: any) {
    console.error('\n❌ Error:', error.message);
  }
}

runDemo().catch(console.error);
